:root {
  --bg: #f7f4ef;
  --bg-strong: #efe8de;
  --text: #1f2328;
  --muted: #5f6670;
  --accent: #0f766e;
  --card: #ffffff;
  --border: #dad2c7;
}

body {
  margin: 0;
  font-family: "Avenir Next", "Segoe UI", sans-serif;
  color: var(--text);
  background:
    radial-gradient(circle at 10% 10%, #fff7e8 0%, transparent 35%),
    radial-gradient(circle at 90% 20%, #d9f3ec 0%, transparent 30%),
    var(--bg);
}

.hero {
  min-height: 72vh;
  padding: 24px clamp(20px, 6vw, 80px);
}

.nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.brand {
  font-weight: 700;
  letter-spacing: 0.4px;
}

.theme-btn {
  border: 1px solid var(--border);
  background: var(--card);
  border-radius: 999px;
  padding: 8px 14px;
  cursor: pointer;
}

.hero-content {
  margin-top: 72px;
  max-width: 720px;
}

.eyebrow {
  color: var(--accent);
  font-size: 12px;
  letter-spacing: 1.8px;
}

h1 {
  margin: 10px 0;
  font-size: clamp(2rem, 4.5vw, 4rem);
  line-height: 1.1;
}

.cta {
  display: inline-block;
  margin-top: 16px;
  text-decoration: none;
  color: #fff;
  background: var(--accent);
  padding: 12px 18px;
  border-radius: 10px;
}

.section {
  padding: 48px clamp(20px, 6vw, 80px);
}

.cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 16px;
}

.card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 18px;
}

.contact-form {
  display: grid;
  gap: 10px;
  max-width: 520px;
}

.contact-form input,
.contact-form textarea {
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 12px;
  font: inherit;
  background: #fff;
}

.contact-form button {
  width: fit-content;
  border: none;
  border-radius: 10px;
  padding: 10px 16px;
  background: var(--accent);
  color: #fff;
  cursor: pointer;
}

.footer {
  padding: 28px;
  text-align: center;
  color: var(--muted);
}

.reveal {
  opacity: 0;
  transform: translateY(16px);
  transition: opacity 420ms ease, transform 420ms ease;
}

.reveal.visible {
  opacity: 1;
  transform: translateY(0);
}

body.dark {
  --bg: #111826;
  --bg-strong: #0e1320;
  --text: #f0f4fa;
  --muted: #b8c1cf;
  --accent: #22c55e;
  --card: #161f31;
  --border: #27334a;
}
'}

Executing write_file with params: {'path': '~/Desktop/guzel-simdi-de-site/script.js', 'content': "const revealElements = document.querySelectorAll('.reveal');

const observer = new IntersectionObserver((entries) => {
  entries.forEach((entry) => {
    if (entry.isIntersecting) {
      entry.target.classList.add('visible');
      observer.unobserve(entry.target);
    }
  });
}, { threshold: 0.12 });

revealElements.forEach((el) => observer.observe(el));

const themeToggle = document.getElementById('themeToggle');
themeToggle?.addEventListener('click', () => {
  document.body.classList.toggle('dark');
});

document.querySelector('.contact-form')?.addEventListener('submit', (event) => {
  event.preventDefault();
  alert('Mesajınız alındı. Teşekkürler.');
});
"}

